insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 0, 'Find the simple interest on ₹5000 at 8% per annum for 3 years.', '₹5000 पर 8% वार्षिक दर से 3 वर्ष का simple interest ज्ञात कीजिए।', 'SI = PRT/100 = 5000×8×3/100 = 1200. Therefore, answer = ₹1200.', 'Simple interest charges the same interest on the original principal every year, so the formula is linear in P, R, and T. Final answer is ₹1200.', 'SI = PRT/100 = 5000×8×3/100 = 1200। अतः answer = ₹1200।', 'Simple interest में हर साल original principal पर same interest लगता है, इसलिए formula P, R, T में linear है। Final answer ₹1200 है।', 'EASY', array['simple-interest','si-ci']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
