insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 4, 'Find the simple interest on ₹6400 at 12% per annum for 2 years.', '₹6400 पर 12% वार्षिक दर से 2 वर्ष का simple interest ज्ञात कीजिए।', 'SI = PRT/100 = 6400×12×2/100 = 1536. Therefore, answer = ₹1536.', 'Simple interest charges the same interest on the original principal every year, so the formula is linear in P, R, and T. Final answer is ₹1536.', 'SI = PRT/100 = 6400×12×2/100 = 1536। अतः answer = ₹1536।', 'Simple interest में हर साल original principal पर same interest लगता है, इसलिए formula P, R, T में linear है। Final answer ₹1536 है।', 'EASY', array['simple-interest','si-ci']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
