insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 5, 'At what annual rate will ₹6000 earn ₹1440 simple interest in 4 years?', '₹6000 पर 4 वर्ष में ₹1440 simple interest पाने के लिए annual rate क्या होगी?', 'R = SI×100/(P×T) = 1440×100/(6000×4) = 6%. Therefore, answer = 6%.', 'Rearrange SI = PRT/100. The rate is the annual percentage of principal that produces the given interest over the stated time. Final answer is 6%.', 'R = SI×100/(P×T) = 1440×100/(6000×4) = 6%। अतः answer = 6%।', 'SI = PRT/100 को rearrange करें। Rate principal का annual percentage है जिससे given interest बनता है। Final answer 6% है।', 'EASY', array['simple-interest','rate']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
