insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 10, 'Find the difference between compound interest and simple interest on ₹10000 at 10% for 2 years.', '₹10000 पर 10% दर से 2 वर्ष के लिए CI और SI का difference ज्ञात कीजिए।', 'For 2 years, CI-SI = P(r/100)² = 10000×(10/100)² = 100. Therefore, answer = ₹100.', 'In compound interest, the second year earns interest on the first year''s interest. That extra interest over SI is P(r/100)^2 for 2 years. Final answer is ₹100.', '2 years के लिए CI-SI = P(r/100)² = 10000×(10/100)² = 100। अतः answer = ₹100।', 'CI में दूसरे साल पहले साल के interest पर भी interest लगता है। यही SI से extra amount है। Final answer ₹100 है।', 'MEDIUM', array['compound-interest','ci-si-difference']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '₹2000', '₹2000', false, 'Reported 2-year SI 10000×10×2/100=2000, not CI-SI difference.', '2-year SI 2000 दे दिया, CI-SI difference नहीं।');
