insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 20, '₹960 simple interest is earned at 8% per annum in 3 years. Find the principal.', '8% वार्षिक दर पर 3 वर्ष में ₹960 simple interest मिला। Principal ज्ञात कीजिए।', 'From SI = PRT/100, P = SI×100/(R×T) = 960×100/(8×3) = 4000. Therefore, answer = ₹4000.', 'Principal is the base amount. When interest, rate, and time are known, reverse the simple-interest formula to isolate P. Final answer is ₹4000.', 'SI = PRT/100 से P = SI×100/(R×T) = 960×100/(8×3) = 4000। अतः answer = ₹4000।', 'Principal base amount है। Interest, rate और time दिए हों तो SI formula reverse करके P निकालते हैं। Final answer ₹4000 है।', 'HARD', array['simple-interest','principal']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
